class TakeSurveyPage{constructor(){this.surveyId=this.getSurveyIdFromUrl(),this.survey=null,this.init()}getSurveyIdFromUrl(){const e=window.location.pathname.split("/");return parseInt(e[e.length-2])}async init(){await this.checkResponseStatus()||await this.loadSurvey()}async checkResponseStatus(){try{return!!(await window.app.apiRequest(`/surveys/${this.surveyId}/check-status`)).has_responded&&(window.location.href=`/surveys/${this.surveyId}/already-responded`,!0)}catch(e){return!1}}async loadSurvey(){const e=document.getElementById("loading"),t=document.getElementById("error-message"),s=document.getElementById("survey-container");try{e.classList.remove("hidden"),t.classList.add("hidden"),s.classList.add("hidden");const n=await window.app.apiRequest(`/surveys/${this.surveyId}/data`);this.survey=n,document.getElementById("survey-title").textContent=this.survey.title,document.getElementById("survey-description").textContent=this.survey.description||"",this.renderQuestions(),e.classList.add("hidden"),s.classList.remove("hidden"),this.setupFormSubmission()}catch(s){e.classList.add("hidden"),t.classList.remove("hidden"),t.textContent="Ошибка загрузки опроса. Возможно, опрос не найден или закрыт."}}renderQuestions(){const e=document.getElementById("questions-container");e.innerHTML="",this.survey.questions&&0!==this.survey.questions.length?this.survey.questions.forEach((t,s)=>{const n=document.createElement("div");n.className="question-card "+(t.is_required?"required":"");let i=`\n                <h4>${t.text}${t.is_required?' <span class="required-mark">*</span>':""}</h4>\n            `;"single_choice"===t.type?(i+='<div class="radio-group">',t.options&&t.options.length>0?t.options.forEach(e=>{i+=`\n                            <label class="radio-option">\n                                <input type="radio" name="question_${t.id}" value="${e}" required="${t.is_required}">\n                                ${e}\n                            </label>\n                        `}):i+='<p class="error">Варианты ответа не найдены</p>',i+="</div>"):"text"===t.type&&(i+=`\n                    <div class="form-group">\n                        <textarea name="question_${t.id}" rows="3" ${t.is_required?"required":""} placeholder="Введите ваш ответ..."></textarea>\n                    </div>\n                `),n.innerHTML=i,e.appendChild(n)}):e.innerHTML='<div class="empty-state"><h2>Вопросов не найдено</h2><p>У этого опроса пока нет вопросов.</p></div>'}setupFormSubmission(){const e=document.getElementById("survey-form"),t=document.getElementById("submit-btn"),s=document.getElementById("success-message");e.addEventListener("submit",async n=>{n.preventDefault();const i=[],r=new FormData(e);for(const[e,t]of r.entries())if(e.startsWith("question_")&&""!==t.trim()){const s=parseInt(e.replace("question_",""));i.push({question_id:s,value:t.trim()})}if(this.validateAnswers(i))try{t.disabled=!0,t.textContent="Отправка...",await window.app.apiRequest(`/surveys/${this.surveyId}/responses`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({answers:i})}),e.classList.add("hidden"),s.classList.remove("hidden"),setTimeout(()=>{window.location.href="/"},3e3)}catch(e){t.disabled=!1,t.textContent="Отправить ответы";const s=document.getElementById("error-message");s.classList.remove("hidden"),s.textContent=e.message||"Ошибка при отправке ответов."}else window.app.showMessage("Пожалуйста, заполните все обязательные поля","error")})}validateAnswers(e){if(!this.survey.questions||0===this.survey.questions.length)return!1;const t={};this.survey.questions.forEach(e=>{t[e.id]=e});for(const t of this.survey.questions)if(t.is_required){const s=e.find(e=>e.question_id===t.id);if(!s||!s.value)return!1}return!0}}document.addEventListener("DOMContentLoaded",()=>{new TakeSurveyPage});